#include <chrono>
#include <sys/socket.h>
#include <netinet/in.h>
#include <arpa/inet.h>
#include <unistd.h>

#define PORT 8888
#define BUFFER_SIZE 1024
#define MAX_PLAYERS 100

struct Vector3 {
    float x, y, z;
};

struct Player {
    int id;
    Vector3 position;
    Vector3 rotation;
    int health;
    int kills;
    int deaths;
    sockaddr_in address;
    std::chrono::steady_clock::time_point lastUpdate;
};

enum PacketType {
    PACKET_CONNECT = 1,
    PACKET_DISCONNECT = 2,
    PACKET_POSITION_UPDATE = 3,
    PACKET_SHOOT = 4,
    PACKET_HIT = 5
};

struct Packet {
    int type;
    int playerId;
    Vector3 position;
    Vector3 rotation;
    Vector3 direction;
    int targetId;
    int damage;
};

class GameServer {
private:
    int sockfd;
    std::map<int, Player> players;
    std::mutex playersMutex;
    int nextPlayerId;
    bool running;

public:
    GameServer() : nextPlayerId(1), running(false) {}

    void start() {
        sockfd = socket(AF_INET, SOCK_DGRAM, 0);
        
        sockaddr_in serverAddr;
        memset(&serverAddr, 0, sizeof(serverAddr));
        serverAddr.sin_family = AF_INET;
        serverAddr.sin_addr.s_addr = INADDR_ANY;
        serverAddr.sin_port = htons(PORT);

        bind(sockfd, (struct sockaddr*)&serverAddr, sizeof(serverAddr));

        std::cout << "Game server started on port " << PORT << std::endl;

        running = true;
        std::thread receiveThread(&GameServer::receivePackets, this);
        std::thread updateThread(&GameServer::updateLoop, this);

        receiveThread.join();
        updateThread.join();
    }

    void stop() {
        running = false;
        close(sockfd);
    }

private:
    void receivePackets() {
        char buffer[BUFFER_SIZE];
        sockaddr_in clientAddr;
        socklen_t addrLen = sizeof(clientAddr);

        while (running) {
            int bytesReceived = recvfrom(sockfd, buffer, BUFFER_SIZE, 0, 
                                        (struct sockaddr*)&clientAddr, &addrLen);

            if (bytesReceived > 0) {
                processPacket(buffer, bytesReceived, clientAddr);
            }
        }
    }

    void processPacket(char* data, int size, sockaddr_in& clientAddr) {
        Packet* packet = (Packet*)data;

        switch (packet->type) {
            case PACKET_CONNECT:
                handleConnect(clientAddr);
                break;
            case PACKET_DISCONNECT:
                handleDisconnect(packet->playerId);
                break;
            case PACKET_POSITION_UPDATE:
                handlePositionUpdate(packet);
                break;
            case PACKET_SHOOT:
                handleShoot(packet);
                break;
            case PACKET_HIT:
                handleHit(packet);
                break;
        }
    }

    void handleConnect(sockaddr_in& clientAddr) {
        std::lock_guard<std::mutex> lock(playersMutex);
        
        int playerId = nextPlayerId++;
        Player newPlayer;
        newPlayer.id = playerId;
        newPlayer.position = {0, 0, 0};
        newPlayer.rotation = {0, 0, 0};
        newPlayer.health = 100;
        newPlayer.kills = 0;
        newPlayer.deaths = 0;
        newPlayer.address = clientAddr;
        newPlayer.lastUpdate = std::chrono::steady_clock::now();

        players[playerId] = newPlayer;

        Packet response;
        response.type = PACKET_CONNECT;
        response.playerId = playerId;
        sendPacket(&response, sizeof(response), clientAddr);

        std::cout << "Player " << playerId << " connected" << std::endl;
        broadcastPlayerList();
    }

    void handleDisconnect(int playerId) {
        std::lock_guard<std::mutex> lock(playersMutex);
        
        players.erase(playerId);
        std::cout << "Player " << playerId << " disconnected" << std::endl;
        
        broadcastPlayerList();
    }

    void handlePositionUpdate(Packet* packet) {
        std::lock_guard<std::mutex> lock(playersMutex);
        
        auto it = players.find(packet->playerId);
        if (it != players.end()) {
            it->second.position = packet->position;
            it->second.rotation = packet->rotation;
            it->second.lastUpdate = std::chrono::steady_clock::now();
            
            broadcastPositionUpdate(packet);
        }
    }

    void handleShoot(Packet* packet) {
        std::lock_guard<std::mutex> lock(playersMutex);
        
        auto shooter = players.find(packet->playerId);
        if (shooter != players.end()) {
            Vector3 rayOrigin = packet->position;
            Vector3 rayDirection = packet->direction;
            
            int hitPlayerId = performRaycast(rayOrigin, rayDirection, packet->playerId);
            
            if (hitPlayerId != -1) {
                Packet hitPacket;
                hitPacket.type = PACKET_HIT;
                hitPacket.playerId = packet->playerId;
                hitPacket.targetId = hitPlayerId;
                hitPacket.damage = 25;
                
                handleHit(&hitPacket);
            }
            
            broadcastShoot(packet);
        }
    }

    void handleHit(Packet* packet) {
        std::lock_guard<std::mutex> lock(playersMutex);
        
        auto target = players.find(packet->targetId);
        auto shooter = players.find(packet->playerId);
        
        if (target != players.end() && shooter != players.end()) {
            target->second.health -= packet->damage;
            
            if (target->second.health <= 0) {
                target->second.health = 0;
                target->second.deaths++;
                shooter->second.kills++;
                
                target->second.position = {0, 0, 0};
                target->second.health = 100;
                
                std::cout << "Player " << packet->playerId << " killed Player " 
                         << packet->targetId << std::endl;
            }
            
            broadcastHit(packet);
        }
    }

    int performRaycast(Vector3 origin, Vector3 direction, int shooterId) {
        float maxDistance = 1000.0f;
        int hitPlayerId = -1;
        float closestDistance = maxDistance;

        for (auto& pair : players) {
            if (pair.first == shooterId) continue;
            
            Player& player = pair.second;
            Vector3 toPlayer = {
                player.position.x - origin.x,
                player.position.y - origin.y,
                player.position.z - origin.z
            };
            
            float distance = sqrt(toPlayer.x * toPlayer.x + 
                                toPlayer.y * toPlayer.y + 
                                toPlayer.z * toPlayer.z);
            
            float dot = toPlayer.x * direction.x + 
                       toPlayer.y * direction.y + 
                       toPlayer.z * direction.z;
            
            if (dot > 0 && distance < closestDistance) {
                float hitRadius = 0.5f;
                Vector3 closestPoint = {
                    origin.x + direction.x * dot,
                    origin.y + direction.y * dot,
                    origin.z + direction.z * dot
                };
                
                float distToPoint = sqrt(
                    (closestPoint.x - player.position.x) * (closestPoint.x - player.position.x) +
                    (closestPoint.y - player.position.y) * (closestPoint.y - player.position.y) +
                    (closestPoint.z - player.position.z) * (closestPoint.z - player.position.z)
                );
                
                if (distToPoint < hitRadius) {
                    closestDistance = distance;
                    hitPlayerId = pair.first;
                }
            }
        }
        
        return hitPlayerId;
    }

    void broadcastPlayerList() {
        for (auto& pair : players) {
            Packet packet;
            packet.type = PACKET_CONNECT;
            
            for (auto& otherPair : players) {
                if (pair.first != otherPair.first) {
                    packet.playerId = otherPair.first;
                    packet.position = otherPair.second.position;
                    sendPacket(&packet, sizeof(packet), pair.second.address);
                }
            }
        }
    }

    void broadcastPositionUpdate(Packet* packet) {
        for (auto& pair : players) {
            if (pair.first != packet->playerId) {
                sendPacket(packet, sizeof(Packet), pair.second.address);
            }
        }
    }

    void broadcastShoot(Packet* packet) {
        for (auto& pair : players) {
            sendPacket(packet, sizeof(Packet), pair.second.address);
        }
    }

    void broadcastHit(Packet* packet) {
        for (auto& pair : players) {
            sendPacket(packet, sizeof(Packet), pair.second.address);
        }
    }

    void sendPacket(void* data, int size, sockaddr_in& addr) {
        sendto(sockfd, data, size, 0, (struct sockaddr*)&addr, sizeof(addr));
    }

    void updateLoop() {
        while (running) {
            std::this_thread::sleep_for(std::chrono::milliseconds(50));
            
            std::lock_guard<std::mutex> lock(playersMutex);
            auto now = std::chrono::steady_clock::now();
            
            std::vector<int> disconnectedPlayers;
            for (auto& pair : players) {
                auto elapsed = std::chrono::duration_cast<std::chrono::seconds>(
                    now - pair.second.lastUpdate).count();
                
                if (elapsed > 30) {
                    disconnectedPlayers.push_back(pair.first);
                }
            }
            
            for (int id : disconnectedPlayers) {
                players.erase(id);
                std::cout << "Player " << id << " timed out" << std::endl;
            }
        }
    }
};

